    workPerPerson[r].tareas_total++;
    if (t.completada) workPerPerson[r].tareas_done++;
    else if (t.vencida) workPerPerson[r].tareas_overdue++;
    else workPerPerson[r].tareas_pending++;
  }
}
for (const c of commitsRecent) {
